parameters.jsCode:
const response = JSON.parse($input.first().json.candidates[0].content.parts[0].text.replace('```json', '').replace('```', '').trim());

return [{
  json: {
    perfilCliente: response.perfilCliente,
    recomendacoes: response.produtosRecomendados,
    cupomDesconto: response.mensagemPersonalizada.match(/cupom[:\s]+(\w+)/i)?.[1] || 'PROMO10',
    mensagemIA: response.mensagemPersonalizada
  }
}];
